const transcript = $('Call Rinat or Leave Voicemail').first().json.reply_text || '';

const userText = transcript.split('\n')
  .filter(l => l.toLowerCase().includes('user:'))
  .map(l => l.replace(/user:/i, '').trim())
  .join(' ');

if (userText.length < 5) {
  return [{ json: { slack_channel: 'C0XXXXXXXX1', slack_text: "⚠ Голос не распознан" } }];
}

// Разбиваем по ключевым именам/темам — ищем где начинается каждая тема
// Паттерны: "скажи Ангелине ...", "запчасти ...", "зарплата ...", "для Марка ..."
const lower = userText.toLowerCase();

// Находим все "точки входа" каждой темы
const markers = [];

const angelinaWords = ['ангелин', 'зарплат'];
const ferasWords = ['ферас', 'запчаст'];

// Ищем позиции всех ключевых слов
for (const word of angelinaWords) {
  let pos = lower.indexOf(word);
  while (pos !== -1) {
    // Откатываемся назад до начала смысловой группы (до предыдущего маркера или "скажи")
    let start = pos;
    const before = lower.lastIndexOf('скажи', pos);
    if (before !== -1 && pos - before < 15) start = before;
    markers.push({ start, topic: 'angelina' });
    pos = lower.indexOf(word, pos + 1);
  }
}

for (const word of ferasWords) {
  let pos = lower.indexOf(word);
  while (pos !== -1) {
    let start = pos;
    const before = lower.lastIndexOf('скажи', pos);
    if (before !== -1 && pos - before < 15) start = before;
    markers.push({ start, topic: 'feras' });
    pos = lower.indexOf(word, pos + 1);
  }
}

// Сортируем по позиции в тексте
markers.sort((a, b) => a.start - b.start);

// Убираем дубли (если два маркера одной темы рядом)
const unique = [];
for (const m of markers) {
  if (!unique.length || unique[unique.length-1].start !== m.start) {
    unique.push(m);
  }
}

// Нарезаем текст по маркерам
const segments = {};
for (let i = 0; i < unique.length; i++) {
  const { start, topic } = unique[i];
  const end = unique[i+1] ? unique[i+1].start : userText.length;
  const chunk = userText.slice(start, end).trim();
  if (!segments[topic]) segments[topic] = [];
  segments[topic].push(chunk);
}

const results = [];

if (segments.angelina) {
  results.push({
    json: {
      slack_channel: 'C0XXXXXXXX1',
      slack_text: `💰 *Для Ангелины (зарплата)*:\n${segments.angelina.join(' ')}`
    }
  });
}

if (segments.feras) {
  results.push({
    json: {
      slack_channel: 'C0XXXXXXXX1',
      slack_text: `🔧 *Для Марка (запчасти)*:\n${segments.feras.join(' ')}`
    }
  });
}

if (results.length === 0) {
  results.push({
    json: {
      slack_channel: 'C0XXXXXXXX1',
      slack_text: `🎙 *Ответ Артёма*:\n${userText}`
    }
  });
}

return results;

const prepared = $('Call Rinat or Leave Voicemail').first().json;

// Берем данные из первого звонка
const originalMessage = prepared.original_message;
const rinatReply = prepared.reply_text; // Твой ответ из транскрипции
const person = prepared.person;

const summaryTitle = `Ответ Артёма для: ${person}`;
const summaryText = [
  `Артём ответил на сообщение из Slack.`,
  `-------------------`,
  `ВОПРОС: ${originalMessage}`,
  `-------------------`,
  `ОТВЕТ РИНАТА: ${rinatReply}`,
  `-------------------`,
  `Статус: Ответ передан клиенту голосом.`
].join('\n');

return [{
  json: {
    summary_title: summaryTitle,
    summary_text: summaryText,
    rinat_reply: rinatReply,
    original_message: originalMessage,
    person: person,
    slack_channel: prepared.slack_channel
  }
}];

const API_KEY = $env.VAPI_API_KEY;
const assistantId = $env.VAPI_ASSISTANT_ID;
const phoneNumberId = $env.VAPI_PHONE_NUMBER_ID;
const rinatNumber = $env.SECRETARY_TARGET_PHONE;

const slackData = $('Slack Test Channel Trigger').first().json || {};
const rawText =
  slackData.text ||
  slackData.event?.text ||
  'Новое сообщение';

try {

  // РЕАЛЬНЫЙ ЗВОНОК
  const callResponse = await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://api.vapi.ai/call/phone',

    headers: {
      'Authorization': `Bearer ${API_KEY}`,
      'Content-Type': 'application/json'
    },

    body: {
      assistantId,
      phoneNumberId,

      customer: {
        number: rinatNumber
      },

      assistantOverrides: {

        // КЛЮЧЕВОЕ:
        // ассистент ждет пока человек скажет хоть что-то
        firstMessageMode: 'assistant-waits-for-user',

        silenceTimeoutSeconds: 25,
        maxDurationSeconds: 120,

        firstMessage:
          `Артём привет. В Слаке написали: ${rawText.slice(0, 250)}. Что ответить?`
      }
    },

    json: true
  });

  // ЖДЕМ ОКОНЧАНИЯ ЗВОНКА
  let status = null;

  for (let i = 0; i < 24; i++) {

    await new Promise(r => setTimeout(r, 5000));

    status = await this.helpers.httpRequest({
      method: 'GET',

      url: `https://api.vapi.ai/call/${callResponse.id}`,

      headers: {
        'Authorization': `Bearer ${API_KEY}`
      },

      json: true
    });

    if (
      status.status === 'ended' ||
      status.status === 'failed'
    ) {
      break;
    }
  }

  // ТРАНСКРИПТ
  const transcript =
    status?.transcript ||
    status?.analysis?.transcript ||
    status?.messages?.map(
      m => `${m.role}: ${m.content}`
    ).join('\n') ||
    '';

  const endedReason =
    status?.endedReason || '';

  // НЕ ОТВЕТИЛ
  const missedReasons = [
    'customer-did-not-answer',
    'no-answer',
    'voicemail',
    'busy',
    'failed'
  ];

  const didNotAnswer =
    missedReasons.includes(endedReason);

  // БЫЛ ЛИ РЕАЛЬНЫЙ ОТВЕТ
  const hasUserSpeech =
    transcript.toLowerCase().includes('user:');

  const isCallRejected =
    didNotAnswer || !hasUserSpeech;

  return [{
    json: {
      call_id: callResponse.id,

      reply_text:
        transcript || 'Нет ответа',

      original_message: rawText,

      is_call_rejected: isCallRejected,

      ended_reason: endedReason,

      slack_text: isCallRejected
        ? '❌ Артём не ответил'
        : '✅ Артём ответил'
    }
  }];

} catch (error) {

  return [{
    json: {

      is_call_rejected: true,

      original_message: rawText,

      reply_text: '',

      slack_text:
        `❌ Ошибка Vapi:\n${error.message}`
    }
  }];
}

const rawText = $('Call Rinat or Leave Voicemail').first().json.original_message || 'Сообщение';

const voiceText = `Артём, ты не взял трубку. Сообщение из Слака: ${rawText}`;
const encoded = encodeURIComponent(voiceText.slice(0, 200));
const audioUrl = `https://translate.google.com/translate_tts?ie=UTF-8&q=${encoded}&tl=ru&client=tw-ob`;

return [{
  json: {
    slack_channel: 'C0XXXXXXXX1',
    slack_text: `📵 *Артём не ответил — голосовое:*\n${audioUrl}`
  }
}];

const slackText = $input.item.json.slack_text;
const slackChannel = $input.item.json.slack_channel || 'C0XXXXXXXX1';

const lines = slackText.split('\n');
const textToSpeak = lines.slice(1).join(' ').trim() || slackText;

const isAngelina = slackText.includes('Ангелин');
const isFeras = slackText.includes('Марк');
const recipientName = isAngelina ? 'Ангелины' : isFeras ? 'Марка' : 'команды';
const emoji = isAngelina ? '💰' : isFeras ? '🔧' : '🎙';

const now = new Date().toLocaleTimeString('ru-RU', { hour: '2-digit', minute: '2-digit' });

const encoded = encodeURIComponent(textToSpeak.slice(0, 200));
const audioUrl = `https://translate.google.com/translate_tts?ie=UTF-8&q=${encoded}&tl=ru&client=tw-ob`;

return {
  json: {
    slack_channel: slackChannel,
    slack_text: `${emoji} *Голосовое для ${recipientName}* · 🎙 Артём · ${now}\n${audioUrl}`
  }
};
